BACK=set('aıouâU'); FRONT=set('eiöüİ')
VL=set('ptkqçşsfhÇ')
def lastvowel(s):
    for c in reversed(s):
        if c in BACK: return 'B'
        if c in FRONT: return 'F'
    return 'B'
def infer_h(forms,lemma):
    # forms: list of (feat,word) EXCLUDING target
    votes=defaultdict(int)
    for feat,w in forms:
        st = lemma if not feat.startswith('V') else lemma[:-3]
        suf=w[len(st):] if w.startswith(st) else ''
        for c in suf:
            if c in BACK: votes['B']+=1;break
            if c in FRONT: votes['F']+=1;break
    if votes: return max(votes,key=votes.get)
    return lastvowel(lemma if not lemma.endswith(('maq','mek')) else lemma[:-3])
def infer_v(forms,lemma):
    for feat,w in forms:
        st= lemma if not feat.startswith('V') else lemma[:-3]
        suf=w[len(st):] if w.startswith(st) else ''
        if suf[:1] in 'dğg': return 'voiced'
        if suf[:1] in 'tqk': return 'voiceless'
    ln=(lemma[:-3] if lemma.endswith(('maq','mek')) else lemma)
    return 'voiceless' if ln[-1:] in VL else 'voiced'

def predict(lemma,feat,h,v):
