    def hv(b,f): return b if h=='B' else f
    def vv(vd,vl): return vd if v=='voiced' else vl
    if feat in ('N;NOM','ADJ;NOM','V;NFIN'): return lemma
    if feat in ('N;ACC','ADJ;ACC'): return st+hv('nı','ni')
    if feat in ('N;GEN','ADJ;GEN'): return st+hv('nıñ','niñ')
    if feat in ('N;DAT','ADJ;DAT'): return st+vv(hv('ğa','ge'),hv('qa','ke'))
    if feat in ('N;LOC','ADJ;LOC'): return st+vv(hv('da','de'),hv('ta','te'))
    if feat in ('N;ABL','ADJ;ABL'): return st+vv(hv('dan','den'),hv('tan','ten'))
    if feat=='V;IMP;SG;2': return st
