    return 'voiceless' if stem(l,f)[-1:] in VL else 'voiced'
def suffix(l,f,w):
    st=stem(l,f); return w[len(st):] if w.startswith(st) else None
def obs_h(others,l):
    votes=set()
    for ff,ww in others:
        s=suffix(l,ff,ww)
        if not s: continue
        for c in s:
            if c in BACK: votes.add('B');break
            if c in FRONT: votes.add('F');break
    return votes
def obs_v(others,l):
    votes=set()
    for ff,ww in others:
        case=ff.split(';')[-1]
        if case not in ('DAT','LOC','ABL'): continue
        s=suffix(l,ff,ww)
        if s and s[:1] in 'dğg': votes.add('voiced')
        elif s and s[:1] in 'tqk': votes.add('voiceless')
    return votes
def predict(l,f,h,v):
    st=stem(l,f)
    def hv(b,ff): return b if h=='B' else ff
    def vv(vd,vl): return vd if v=='voiced' else vl
    c=f.split(';')[-1]
    if f in('N;NOM','ADJ;NOM','V;NFIN'): return l
    if c=='ACC': return st+hv('nı','ni')
    if c=='GEN': return st+hv('nıñ','niñ')
    if c=='DAT': return st+vv(hv('ğa','ge'),hv('qa','ke'))
    if c=='LOC': return st+vv(hv('da','de'),hv('ta','te'))
    if c=='ABL': return st+vv(hv('dan','den'),hv('tan','ten'))
    if f=='V;IMP;SG;2': return st
    if f=='V;SG;3;PRS': return st+('y' if st[-1:] in (BACK|FRONT) else hv('a','e'))
    if f=='V;SG;3;PST': return st+('dı' if h=='B' else ('ti' if v=='voiceless' else 'di'))
    return l
for MODE in ['rule','override']:
