    if poss and c in('DAT','LOC','ABL') and st[-1:] in VOW:
        return st+({'DAT':('na','ne'),'LOC':('nda','nde'),'ABL':('ndan','nden')}[c][0 if HB else 1])
    if c=='ACC': return st+('nı' if HB else 'ni')
    if c=='GEN': return st+('nıñ' if HB else 'niñ')
    vd=(v=='voiced')
    if c=='DAT': return st+((('ğa' if vd else 'qa')) if HB else (('ge' if vd else 'ke')))
    if c=='LOC': return st+((('da' if vd else 'ta')) if HB else (('de' if vd else 'te')))
    if c=='ABL': return st+((('dan' if vd else 'tan')) if HB else (('den' if vd else 'ten')))
    if f=='V;IMP;SG;2': return st
    if f=='V;SG;3;PRS': return st+('y' if st[-1:] in VOW else ('a' if HB else 'e'))
